const char *lc_state_id_block_name(int32_t state_id) {
  if (state_id < 0 || state_id > LC_STATE_MAP_MAX) return LC_STATE_NAME_UNKNOWN;
  const char *n = LC_STATE_BLOCK_NAME[state_id];
  return n && n[0] ? n : LC_STATE_NAME_UNKNOWN;
}
